var { createTerminal } = require("./terminal");

var MAX_TERMINALS = 10;
var SCROLLBACK_MAX = 50 * 1024; // 50 KB per terminal

/**
 * Create a terminal manager for a project.
 * Manages persistent PTY sessions with scrollback buffering.
 * opts: { cwd, send, sendTo }
 */
function createTerminalManager(opts) {
  var cwd = opts.cwd;
  var send = opts.send;
  var sendTo = opts.sendTo;

  var nextId = 1;
  var terminals = new Map(); // id -> terminal session

  function create(cols, rows) {
    if (terminals.size > MAX_TERMINALS) return null;

    var id = nextId++;
    var term = createTerminal({
      cwd: cwd,
      cols: cols,
      rows: rows,
      onData: function (data) {
        send({ type: "terminal-data", id: id, data: data });
      },
      onExit: function () {
        terminals.delete(id);
        send({ type: "terminal-exit", id: id });
      },
    });

    term.scrollback = "";
    term.scrollbackSize = 0;

    term.onData(function (data) {
      term.scrollback += data;
      term.scrollbackSize += data.length;
      if (term.scrollbackSize > SCROLLBACK_MAX) {
        // Trim oldest data
        var excess = term.scrollbackSize - SCROLLBACK_MAX;
        term.scrollback = term.scrollback.slice(excess);
        term.scrollbackSize = SCROLLBACK_MAX;
      }
    });

    terminals.set(id, term);
    send({ type: "terminal-created", id: id });
    return id;
  }

  function write(id, data) {
    var term = terminals.get(id);
    if (!term) return false;
    term.write(data);
    return true;
  }

  function resize(id, cols, rows) {
    var term = terminals.get(id);
    if (!term) return false;
    term.resize(cols, rows);
    return true;
  }

  function getScrollback(id) {
    var term = terminals.get(id);
    if (!term) return null;
    return term.scrollback;
  }

  return {
    create,
    write,
    resize,
    getScrollback,
  };
}

module.exports = {
  createTerminalManager,
};
